const p = $input.first().json;

if (!p.endpoint || !p.method || !p.headers) {
  throw new Error('Payload inválido: endpoint, method e headers são obrigatórios');
}

const baseUrl = 'http://177.38.10.218:8082/datasnap/rest/TSMApi';
const url = `${baseUrl}/"${p.endpoint}"`;

const fetchOptions = {
  method: p.method,
  headers: p.headers,
  rejectUnauthorized: false,
  timeout: 30000,
};

if (p.body && p.method !== 'GET') {
  fetchOptions.body = typeof p.body === 'string' ? p.body : JSON.stringify(p.body);
}

try {
  const response = await this.helpers.httpRequest({
    url,
    method: p.method,
    headers: p.headers,
    body: p.body,
    json: false,
    returnFullResponse: true,
    simple: false,
    timeout: 30000,
  });

  let body = response.body;
  if (typeof body === 'string' && body.trim()) {
    try { body = JSON.parse(body); } catch {}
  }

  return [{
    json: {
      status: response.statusCode || 200,
      body: body || null,
    },
  }];
} catch (err) {
  return [{
    json: {
      status: 500,
      body: null,
      error: err.message || 'Erro ao conectar no Proxis',
    },
  }];
}
